import { Marker, Popup } from "react-leaflet";
import L from "leaflet";

const planeIcon = new L.Icon({
  iconUrl: "/plane.png",
  iconSize: [40, 40],
  iconAnchor: [20, 20],
});

export default function PlaneMarker({ position, flightNo }) {
  return (
    <Marker position={position} icon={planeIcon}>
      <Popup>
        <div>
          <strong>✈️ Flight:</strong> {flightNo || "Unknown"} <br />
          <strong>Lat:</strong> {position[0].toFixed(2)} <br />
          <strong>Lng:</strong> {position[1].toFixed(2)}
        </div>
      </Popup>
    </Marker>
  );
}
